	s.AddTool(
		mcplib.NewTool("accounts_outcome-groups_api-link-for-accounts",
			mcplib.WithDescription("Link an outcome into the outcome group. The outcome to link can either be specified by a PUT to the link URL for a specific outcome (the outcome_id in the PUT URLs) or by supplying the information for a new outcome (title, description, ratings, mastery_points) in a POST to the collection. If linking an existing outcome, the outcome_id must identify an outcome available to this context; i.e. an outcome owned by this group's context, an outcome owned by an associated account, or a global outcome. With outcome_id present, any other parameters (except move_from) are ignored. If defining a new outcome, the outcome is created in the outcome group's context using the provided title, description, ratings, and mastery points; the title is required but all other fields are optional. The new outcome is then linked into the outcome group. If ratings are provided when creating a new outcome, an embedded rubric criterion is included in the new outcome. This criterion's mastery_points default to the maximum points in the highest rating if not specified in the mastery_points parameter. Any ratings lacking a description are given a default of 'No description'. Any ratings lacking a point value are given a default of 0. If no ratings are provided, the mastery_points parameter is ignored. Required: account_id, id, title. Optional: calculation_int, calculation_method, description (plus 7 more)."),
			mcplib.WithString("account_id", mcplib.Required(), mcplib.Description("ID of the account")),
			mcplib.WithString("id", mcplib.Required(), mcplib.Description("Scope response to id")),
			mcplib.WithString("calculation_int", mcplib.Description("The new calculation int.")),
			mcplib.WithString("calculation_method", mcplib.Description("The new calculation method.")),
			mcplib.WithString("description", mcplib.Description("The description of the new outcome.")),
			mcplib.WithString("display_name", mcplib.Description("A friendly name shown in reports for outcomes with cryptic titles, such as common core...")),
			mcplib.WithString("mastery_points", mcplib.Description("The mastery threshold for the embedded rubric criterion.")),
			mcplib.WithString("move_from", mcplib.Description("The ID of the old outcome group. Only used if outcome_id is present.")),
			mcplib.WithString("outcome_id", mcplib.Description("The ID of the existing outcome to link.")),
			mcplib.WithString("ratings[][description]", mcplib.Description("[String] The description of a rating level for the embedded rubric criterion.")),
			mcplib.WithString("ratings[][points]", mcplib.Description("[Integer] The points corresponding to a rating level for the embedded rubric criterion.")),
			mcplib.WithString("title", mcplib.Required(), mcplib.Description("The title of the new outcome. Required if outcome_id is absent.")),
			mcplib.WithString("vendor_guid", mcplib.Description("A custom GUID for the learning standard.")),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("POST", "/accounts/{account_id}/outcome_groups/{id}/outcomes", []mcpParamBinding{{PublicName: "account_id", WireName: "account_id", Location: "path"},{PublicName: "id", WireName: "id", Location: "path"},{PublicName: "calculation_int", WireName: "calculation_int", Location: "body"},{PublicName: "calculation_method", WireName: "calculation_method", Location: "body"},{PublicName: "description", WireName: "description", Location: "body"},{PublicName: "display_name", WireName: "display_name", Location: "body"},{PublicName: "mastery_points", WireName: "mastery_points", Location: "body"},{PublicName: "move_from", WireName: "move_from", Location: "body"},{PublicName: "outcome_id", WireName: "outcome_id", Location: "body"},{PublicName: "ratings[][description]", WireName: "ratings[][description]", Location: "body"},{PublicName: "ratings[][points]", WireName: "ratings[][points]", Location: "body"},{PublicName: "title", WireName: "title", Location: "body"},{PublicName: "vendor_guid", WireName: "vendor_guid", Location: "body"}, }, []string{"account_id","id", }),
	)
