	s.AddTool(
		mcplib.NewTool("users_service-credentials-activity-stream-for",
			mcplib.WithDescription("Returns the current user's global activity stream, paginated. There are many types of objects that can be returned in the activity stream. All object types have the same basic set of shared attributes: !!!javascript { 'created_at': '2011-07-13T09:12:00Z', 'updated_at': '2011-07-25T08:52:41Z', 'id': 1234, 'title': 'Stream Item Subject', 'message': 'This is the body text of the activity stream item. It is plain-text, and can be multiple paragraphs.', 'type': 'DiscussionTopic|Conversation|Message|Submission|Conference|Collaboration|AssessmentRequest...', 'read_state': false, 'context_type': 'course', // course|group 'course_id': 1, 'group_id': null, 'html_url': 'http://...' // URL to the Canvas web UI for this stream item } In addition, each item type has its own set of attributes available. DiscussionTopic: !!!javascript { 'type': 'DiscussionTopic', 'discussion_topic_id': 1234, 'total_root_discussion_entries': 5, 'require_initial_post': true, 'user_has_posted': true, 'root_discussion_entries': { ... } } For DiscussionTopic, the message is truncated at 4kb. Announcement: !!!javascript { 'type': 'Announcement', 'announcement_id': 1234, 'total_root_discussion_entries': 5, 'require_initial_post': true, 'user_has_posted': null, 'root_discussion_entries': { ... } } For Announcement, the message is truncated at 4kb. Conversation: !!!javascript { 'type': 'Conversation', 'conversation_id': 1234, 'private': false, 'participant_count': 3, } Message: !!!javascript { 'type': 'Message', 'message_id': 1234, 'notification_category': 'Assignment Graded' } Submission: Returns an {api:Submissions:Submission Submission} with its Course and Assignment data. Conference: !!!javascript { 'type': 'Conference', 'web_conference_id': 1234 } Collaboration: !!!javascript { 'type': 'Collaboration', 'collaboration_id': 1234 } AssessmentRequest: !!!javascript { 'type': 'AssessmentRequest', 'assessment_request_id': 1234 }. Optional: only_active_courses."),
			mcplib.WithString("only_active_courses", mcplib.Description("If true, will only return objects for courses the user is actively participating in")),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("GET", "/users/self/activity_stream", []mcpParamBinding{{PublicName: "only_active_courses", WireName: "only_active_courses", Location: "query"}, }, []string{ }),
	)
