	s.AddTool(
		mcplib.NewTool("users_content-migrations_content-list-for-users",
			mcplib.WithDescription("Enumerates the content available for selective import in a tree structure. Each node provides a +property+ copy argument that can be supplied to the {api:ContentMigrationsController#update Update endpoint} to selectively copy the content associated with that tree node and its children. Each node may also provide a +sub_items_url+ or an array of +sub_items+ which you can use to obtain copy parameters for a subset of the resources in a given node. If no +type+ is sent you will get a list of the top-level sections in the content. It will look something like this: [{ 'type': 'course_settings', 'property': 'copy[all_course_settings]', 'title': 'Course Settings' }, { 'type': 'context_modules', 'property': 'copy[all_context_modules]', 'title': 'Modules', 'count': 5, 'sub_items_url': 'http://example.com/api/v1/courses/22/content_migrations/77/selective_data?type=context_modules' }, { 'type': 'assignments', 'property': 'copy[all_assignments]', 'title': 'Assignments', 'count': 2, 'sub_items_url': 'http://localhost:3000/api/v1/courses/22/content_migrations/77/selective_data?type=assignments' }] When a +type+ is provided, nodes may be further divided via +sub_items+. For example, using +type=assignments+ results in a node for each assignment group and a sub_item for each assignment, like this: [{ 'type': 'assignment_groups', 'title': 'An Assignment Group', 'property': 'copy[assignment_groups][id_i855cf145e5acc7435e1bf1c6e2126e5f]', 'sub_items': [{ 'type': 'assignments', 'title': 'Assignment 1', 'property': 'copy[assignments][id_i2102a7fa93b29226774949298626719d]' }, { 'type': 'assignments', 'title': 'Assignment 2', 'property': 'copy[assignments][id_i310cba275dc3f4aa8a3306bbbe380979]' }] }] To import the items corresponding to a particular tree node, use the +property+ as a parameter to the {api:ContentMigrationsController#update Update endpoint} and assign a value of 1, for example: copy[assignments][id_i310cba275dc3f4aa8a3306bbbe380979]=1 You can include multiple copy parameters to selectively import multiple items or groups of items. Required: user_id, id. Optional: type['context_modules'|'assignments'|'quizzes'|'assessment_question_banks'|'discussion_topics'|'wiki_pages'|'context_external_tools'|'tool_profiles'|'announcements'|'calendar_events'|'rubrics'|'groups'|'learning_outcomes'|'attachments']."),
			mcplib.WithString("user_id", mcplib.Required(), mcplib.Description("ID of the user")),
			mcplib.WithString("id", mcplib.Required(), mcplib.Description("Scope response to id")),
			mcplib.WithString("type[\"context_modules\"|\"assignments\"|\"quizzes\"|\"assessment_question_banks\"|\"discussion_topics\"|\"wiki_pages\"|\"context_external_tools\"|\"tool_profiles\"|\"announcements\"|\"calendar_events\"|\"rubrics\"|\"groups\"|\"learning_outcomes\"|\"attachments\"]", mcplib.Description("The type of content to enumerate.")),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("GET", "/users/{user_id}/content_migrations/{id}/selective_data", []mcpParamBinding{{PublicName: "user_id", WireName: "user_id", Location: "path"},{PublicName: "id", WireName: "id", Location: "path"},{PublicName: "type[\"context_modules\"|\"assignments\"|\"quizzes\"|\"assessment_question_banks\"|\"discussion_topics\"|\"wiki_pages\"|\"context_external_tools\"|\"tool_profiles\"|\"announcements\"|\"calendar_events\"|\"rubrics\"|\"groups\"|\"learning_outcomes\"|\"attachments\"]", WireName: "type[\"context_modules\"|\"assignments\"|\"quizzes\"|\"assessment_question_banks\"|\"discussion_topics\"|\"wiki_pages\"|\"context_external_tools\"|\"tool_profiles\"|\"announcements\"|\"calendar_events\"|\"rubrics\"|\"groups\"|\"learning_outcomes\"|\"attachments\"]", Location: "query"}, }, []string{"user_id","id", }),
	)
	s.AddTool(
		mcplib.NewTool("users_content-migrations_create-for-users",
			mcplib.WithDescription("Create a content migration. If the migration requires a file to be uploaded the actual processing of the file will start once the file upload process is completed. File uploading works as described in the {file:file.file_uploads.html File Upload Documentation} except that the values are set on a *pre_attachment* sub-hash. For migrations that don't require a file to be uploaded, like course copy, the processing will begin as soon as the migration is created. You can use the {api:ProgressController#show Progress API} to track the progress of the migration. The migration's progress is linked to with the _progress_url_ value. The two general workflows are: If no file upload is needed: 1. POST to create 2. Use the {api:ProgressController#show Progress} specified in _progress_url_ to monitor progress For file uploading: 1. POST to create with file info in *pre_attachment* 2. Do {file:file.file_uploads.html file upload processing} using the data in the *pre_attachment* data 3. {api:ContentMigrationsController#show GET} the ContentMigration 4. Use the {api:ProgressController#show Progress} specified in _progress_url_ to monitor progress (required if doing .zip file upload). Required: user_id, migration_type, pre_attachment, settings. Optional: date_shift_options, select, selective_import."),
			mcplib.WithString("user_id", mcplib.Required(), mcplib.Description("ID of the user")),
			mcplib.WithString("date_shift_options", mcplib.Description("Date shift options")),
			mcplib.WithString("migration_type", mcplib.Required(), mcplib.Description("The type of the migration.")),
			mcplib.WithString("pre_attachment", mcplib.Required(), mcplib.Description("Pre attachment")),
			mcplib.WithString("select", mcplib.Description("For +course_copy_importer+ migrations, this parameter allows you to select the objects to...")),
			mcplib.WithString("selective_import", mcplib.Description("If set, perform a selective import instead of importing all content.")),
			mcplib.WithString("settings", mcplib.Required(), mcplib.Description("Settings")),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("POST", "/users/{user_id}/content_migrations", []mcpParamBinding{{PublicName: "user_id", WireName: "user_id", Location: "path"},{PublicName: "date_shift_options", WireName: "date_shift_options", Location: "body"},{PublicName: "migration_type", WireName: "migration_type", Location: "body"},{PublicName: "pre_attachment", WireName: "pre_attachment", Location: "body"},{PublicName: "select", WireName: "select", Location: "body"},{PublicName: "selective_import", WireName: "selective_import", Location: "body"},{PublicName: "settings", WireName: "settings", Location: "body"}, }, []string{"user_id", }),
	)
